import{_ as p,c as r}from"./app.90a21e26.js";const t={},o=r('<h1 id="_07-\u5982\u4F55\u9AD8\u6548\u586B\u5199\u8F6F\u4EF6\u7F3A\u9677\u62A5\u544A" tabindex="-1"><a class="header-anchor" href="#_07-\u5982\u4F55\u9AD8\u6548\u586B\u5199\u8F6F\u4EF6\u7F3A\u9677\u62A5\u544A" aria-hidden="true">#</a> 07\uFF1A\u5982\u4F55\u9AD8\u6548\u586B\u5199\u8F6F\u4EF6\u7F3A\u9677\u62A5\u544A\uFF1F</h1><p>\u5728\u4E0A\u4E00\u7BC7\u6587\u7AE0\u4E2D\uFF0C\u6211\u4E3A\u4F60\u4ECB\u7ECD\u4E86\u6D4B\u8BD5\u8986\u76D6\u7387\u7684\u6982\u5FF5\uFF0C\u5E76\u91CD\u70B9\u4ECB\u7ECD\u4E86\u4EE3\u7801\u8986\u76D6\u7387\u7684\u5E94\u7528\u4EF7\u503C\u4EE5\u53CA\u5C40\u9650\u6027\u3002\u4ECA\u5929\u6211\u4F1A\u4E3A\u4F60\u4ECB\u7ECD\u5982\u4F55\u624D\u80FD\u5199\u51FA\u4E00\u4EFD\u9AD8\u6548\u7684\u8F6F\u4EF6\u7F3A\u9677\u62A5\u544A\u3002</p><p>\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u9700\u8981\u5229\u7528\u5BF9\u9700\u6C42\u7684\u7406\u89E3\u3001\u9AD8\u6548\u7684\u6267\u884C\u529B\u4EE5\u53CA\u4E25\u5BC6\u7684\u903B\u8F91\u63A8\u7406\u80FD\u529B\uFF0C\u8FC5\u901F\u627E\u51FA\u8F6F\u4EF6\u4E2D\u7684\u6F5C\u5728\u7F3A\u9677\uFF0C\u5E76\u4EE5\u7F3A\u9677\u62A5\u544A\u7684\u5F62\u5F0F\u9012\u4EA4\u7ED9\u5F00\u53D1\u56E2\u961F\uFF0C\u8FD9\u770B\u8D77\u6765\u662F\u4E0D\u662F\u6709\u70B9\u50CF\u4FA6\u63A2\u67EF\u5357\u5462\u3002</p><p><strong>\u7F3A\u9677\u62A5\u544A\u662F\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u4E0E\u5F00\u53D1\u5DE5\u7A0B\u5E08\u4EA4\u6D41\u6C9F\u901A\u7684\u91CD\u8981\u6865\u6881\uFF0C\u4E5F\u662F\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u65E5\u5E38\u5DE5\u4F5C\u7684\u91CD\u8981\u8F93\u51FA</strong>\u3002 \u4F5C\u4E3A\u4F18\u79C0\u7684\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\uFF0C\u6700\u57FA\u672C\u7684\u4E00\u9879\u6280\u80FD\u5C31\u662F\uFF0C\u628A\u53D1\u73B0\u7684\u7F3A\u9677\u51C6\u786E\u65E0\u6B67\u4E49\u5730\u8868\u8FBE\u6E05\u695A\u3002</p><p>\u201C\u51C6\u786E\u65E0\u6B67\u4E49\u5730\u8868\u8FBE\u201D\u610F\u5473\u7740\uFF0C\u5F00\u53D1\u5DE5\u7A0B\u5E08\u53EF\u4EE5\u6839\u636E\u7F3A\u9677\u62A5\u544A\u5FEB\u901F\u7406\u89E3\u7F3A\u9677\uFF0C\u5E76\u7CBE\u786E\u5B9A\u4F4D\u95EE\u9898\u3002\u540C\u65F6\uFF0C\u901A\u8FC7\u8FD9\u4E2A\u7F3A\u9677\u62A5\u544A\uFF0C\u5F00\u53D1\u7ECF\u7406\u53EF\u4EE5\u51C6\u786E\u9884\u4F30\u7F3A\u9677\u4FEE\u590D\u7684\u4F18\u5148\u7EA7\u3001\u4EA7\u54C1\u7ECF\u7406\u53EF\u4EE5\u4E86\u89E3\u7F3A\u9677\u5BF9\u7528\u6237\u6216\u4E1A\u52A1\u7684\u5F71\u54CD\u4EE5\u53CA\u4E25\u91CD\u6027\u3002</p><p>\u53EF\u89C1\uFF0C<em>\u7F3A\u9677\u62A5\u544A\u672C\u8EAB\u7684\u8D28\u91CF\u5C06\u76F4\u63A5\u5173\u7CFB\u5230\u7F3A\u9677\u88AB\u4FEE\u590D\u7684\u901F\u5EA6\u4EE5\u53CA\u5F00\u53D1\u5DE5\u7A0B\u5E08\u7684\u6548\u7387\uFF0C\u540C\u65F6\u8FD8\u4F1A\u5F71\u54CD\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u7684\u4FE1\u7528\u3001\u6D4B\u8BD5\u4E0E\u5F00\u53D1\u4EBA\u5458\u534F\u4F5C\u7684\u6709\u6548\u6027</em>\u3002</p><p>\u90A3\u4E48\uFF0C\u5982\u4F55\u624D\u80FD\u5199\u51FA\u4E00\u4EFD\u9AD8\u6548\u7684\u7F3A\u9677\u62A5\u544A\u5462\uFF1F\u6216\u8005\u8BF4\uFF0C\u4E00\u4EFD\u597D\u7684\u7F3A\u9677\u62A5\u544A\u9700\u8981\u5305\u62EC\u54EA\u4E9B\u5177\u4F53\u5185\u5BB9\u5462\uFF1F</p><p>\u4F60\u53EF\u80FD\u89C9\u5F97\u8FD9\u5E76\u4E0D\u662F\u4EC0\u4E48\u96BE\u4E8B\u513F\uFF0C\u6BD5\u7ADF\u8F6F\u4EF6\u4F01\u4E1A\u901A\u5E38\u90FD\u6709\u7F3A\u9677\u7BA1\u7406\u7CFB\u7EDF\uFF0C\u6BD4\u5982\u5178\u578B\u7684 ALM\uFF08\u4EE5\u524D\u7684 Quality Center\uFF09\u3001JIRA\u3001Bugzilla\u3001BugFree \u548C Mantis \u7B49\u3002\u5F53\u4F7F\u7528\u8FD9\u7C7B\u7CFB\u7EDF\u9012\u4EA4\u7F3A\u9677\u65F6\uFF0C\u4F1A\u81EA\u52A8\u751F\u6210\u6A21\u677F\uFF0C\u4F60\u53EA\u8981\u6309\u7167\u5176\u4E2D\u7684\u5FC5\u586B\u5B57\u6BB5\u63D0\u4F9B\u7F3A\u9677\u7684\u8BE6\u7EC6\u4FE1\u606F\u5C31\u53EF\u4EE5\u4E86\u3002</p><p>\u5F88\u591A\u65F6\u5019\uFF0C\u4F60\u4E0D\u7528\u60F3\u5E94\u8BE5\u63D0\u4F9B\u4E9B\u4EC0\u4E48\u4FE1\u606F\uFF0C\u7CFB\u7EDF\u4F1A\u5F15\u5BFC\u4F60\u63D0\u4F9B\u76F8\u5173\u7684\u4FE1\u606F\u3002\u4F46\u662F\uFF0C\u4F60\u6709\u4ED4\u7EC6\u60F3\u8FC7\u4E3A\u4EC0\u4E48\u8981\u586B\u5199\u8FD9\u4E9B\u5B57\u6BB5\uFF0C\u8FD9\u4E9B\u5B57\u6BB5\u90FD\u8D77\u4EC0\u4E48\u4F5C\u7528\uFF0C\u4EE5\u53CA\u6BCF\u4E2A\u5B57\u6BB5\u7684\u5185\u5BB9\u5177\u4F53\u5E94\u8BE5\u600E\u4E48\u586B\u5199\u5417\uFF1F</p><p><strong>\u4F60\u5FC5\u987B\u7262\u7262\u8BB0\u4F4F\u7684\u662F\uFF0C\u597D\u7684\u7F3A\u9677\u62A5\u544A\u7EDD\u5BF9\u4E0D\u662F\u5927\u91CF\u4FE1\u606F\u7684\u5806\u53E0\uFF0C\u800C\u662F\u4EE5\u9AD8\u6548\u7684\u65B9\u5F0F\u63D0\u4F9B\u51C6\u786E\u6709\u7528\u7684\u4FE1\u606F</strong>\u3002</p><p>\u63A5\u4E0B\u6765\uFF0C\u6211\u5C31\u5E26\u4F60\u4E00\u8D77\u53BB\u770B\u4E00\u4EFD\u9AD8\u6548\u7684\u7F3A\u9677\u62A5\u544A\u4E3B\u8981\u7531\u54EA\u4E9B\u90E8\u5206\u7EC4\u6210\uFF0C\u4EE5\u53CA\u6BCF\u90E8\u5206\u5185\u5BB9\u7684\u5173\u952E\u70B9\u662F\u4EC0\u4E48\u3002</p><p><strong>\u7F3A\u9677\u6807\u9898</strong><em>\u7F3A\u9677\u6807\u9898\u901A\u5E38\u662F\u522B\u4EBA\u6700\u5148\u770B\u5230\u7684\u90E8\u5206\uFF0C\u662F\u5BF9\u7F3A\u9677\u7684\u6982\u62EC\u6027\u63CF\u8FF0\uFF0C\u901A\u5E38\u91C7\u7528\u201C\u5728\u4EC0\u4E48\u60C5\u51B5\u4E0B\u53D1\u751F\u4E86\u4EC0\u4E48\u95EE\u9898\u201D\u7684\u6A21\u5F0F</em>\u3002</p><p><strong>\u9996\u5148\uFF0C\u5BF9\u201C\u4EC0\u4E48\u95EE\u9898\u201D\u7684\u63CF\u8FF0\u4E0D\u4EC5\u8981\u505A\u5230\u6E05\u6670\u7B80\u6D01\uFF0C\u6700\u5173\u952E\u662F\u8981\u8DB3\u591F\u5177\u4F53\uFF0C\u5207\u5FCC\u4E0D\u80FD\u91C7\u7528\u8FC7\u4E8E\u7B3C\u7EDF\u7684\u63CF\u8FF0\u3002\u63CF\u8FF0\u201C\u4EC0\u4E48\u95EE\u9898\u201D\u7684\u540C\u65F6\u8FD8\u5FC5\u987B\u6E05\u695A\u5730\u8868\u8FF0\u53D1\u751F\u95EE\u9898\u65F6\u7684\u4E0A\u4E0B\u6587\uFF0C\u4E5F\u5C31\u662F\u95EE\u9898\u51FA\u73B0\u7684\u573A\u666F</strong>\u3002</p><p>\u201C\u7528\u6237\u4E0D\u80FD\u6B63\u5E38\u767B\u5F55\u201D\u201C\u641C\u7D22\u529F\u80FD\u6709\u95EE\u9898\u201D\u548C\u201C\u7528\u6237\u4FE1\u606F\u9875\u9762\u7684\u5730\u5740\u680F\u4F4D\u7F6E\u4E0D\u6B63\u786E\u201D\u7B49\uFF0C\u8FD9\u6837\u7684\u63CF\u8FF0\u4F1A\u7ED9\u4EBA\u201C\u8BF4\u4E86\u7B49\u4E8E\u6CA1\u8BF4\u201D\u7684\u611F\u89C9\u3002\u8FD9\u6837\u7684\u63CF\u8FF0\uFF0C\u5F88\u5BB9\u6613\u5F15\u53D1\u5F00\u53D1\u5DE5\u7A0B\u5E08\u7684\u53CD\u611F\u548C\u62B5\u89E6\u60C5\u7EEA\uFF0C\u4ECE\u800C\u9020\u6210\u7F3A\u9677\u88AB\u62D2\u7EDD\u4FEE\u6539\uFF08reject\uFF09\u3002\u540C\u65F6\uFF0C\u8FD8\u4F1A\u9020\u6210\u7F3A\u9677\u7BA1\u7406\u4E0A\u7684\u56F0\u96BE\u4EE5\u53CA\u8FC7\u7A0B\u7684\u4F4E\u6548\u3002</p><p>\u6BD4\u5982\uFF0C\u5F53\u4F60\u53D1\u73B0\u4E86\u4E00\u4E2A\u83DC\u5355\u680F\u4E0A\u67D0\u4E2A\u6761\u76EE\u7F3A\u5931\u7684\u95EE\u9898\uFF0C\u5728\u9012\u4EA4\u7F3A\u9677\u62A5\u544A\u524D\uFF0C\u901A\u5E38\u4F1A\u53BB\u7F3A\u9677\u7BA1\u7406\u7CFB\u7EDF\u641C\u7D22\u4E00\u4E0B\u662F\u5426\u5DF2\u7ECF\u6709\u4EBA\u9012\u4EA4\u8FC7\u7C7B\u4F3C\u7684\u7F3A\u9677\u3002</p><p>\u5F53\u4F60\u4EE5\u201C\u83DC\u5355\u680F\u201D\u4E3A\u5173\u952E\u5B57\u641C\u7D22\u65F6\uFF0C\u4F60\u53EF\u80FD\u4F1A\u5F97\u5230\u4E00\u5806\u201C\u83DC\u5355\u680F\u6709\u95EE\u9898\u201D\u7684\u7F3A\u9677\uFF0C\u5982\u679C\u7F3A\u9677\u6807\u9898\u7684\u63CF\u8FF0\u8FC7\u4E8E\u7B3C\u7EDF\uFF0C\u4F60\u5C31\u4E0D\u5F97\u4E0D\u70B9\u51FB\u8FDB\u5165\u6BCF\u4E2A\u5DF2\u77E5\u7F3A\u9677\u70B9\u53BB\u770B\u7EC6\u8282\u63CF\u8FF0\uFF0C\u8FD9\u5C31\u4F1A\u5927\u5927\u964D\u4F4E\u4F60\u7684\u5DE5\u4F5C\u6548\u7387\u3002</p><p>\u6240\u4EE5\uFF0C\u5982\u679C\u7F3A\u9677\u6807\u9898\u672C\u8EAB\u5C31\u80FD\u6982\u62EC\u6027\u5730\u63CF\u8FF0\u5177\u4F53\u95EE\u9898\uFF0C\u4F60\u5C31\u53EF\u4EE5\u901A\u8FC7\u9605\u8BFB\u6807\u9898\u5224\u65AD\u7C7B\u4F3C\u7684\u7F3A\u9677\u662F\u5426\u88AB\u63D0\u4EA4\u8FC7\uFF0C\u5927\u5927\u63D0\u9AD8\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u63D0\u4EA4\u7F3A\u9677\u62A5\u544A\u7684\u6548\u7387\u3002</p><p><strong>\u5176\u6B21\uFF0C\u6807\u9898\u5E94\u8BE5\u5C3D\u53EF\u80FD\u63CF\u8FF0\u95EE\u9898\u672C\u8D28\uFF0C\u800C\u907F\u514D\u53EA\u505C\u7559\u5728\u95EE\u9898\u7684\u8868\u9762</strong>\u3002</p><p>\u6BD4\u5982\uFF0C\u201C\u5546\u54C1\u91D1\u989D\u8F93\u5165\u6846\uFF0C\u53EF\u4EE5\u8F93\u5165\u82F1\u6587\u5B57\u6BCD\u548C\u5176\u4ED6\u5B57\u7B26\u201D\u8FD9\u4E2A\u63CF\u8FF0\u5C31\u53EA\u63CF\u8FF0\u4E86\u95EE\u9898\u7684\u8868\u9762\u73B0\u8C61\uFF0C\u800C\u91C7\u7528\u8BF8\u5982\u201C\u5546\u54C1\u91D1\u989D\u8F93\u5165\u6846\uFF0C\u6CA1\u6709\u5BF9\u8F93\u5165\u5185\u5BB9\u505A\u6821\u9A8C\u201D\u7684\u65B9\u5F0F\uFF0C\u5C31\u53EF\u4EE5\u900F\u8FC7\u6807\u9898\u770B\u5230\u7F3A\u9677\u7684\u672C\u8D28\uFF0C\u8FD9\u6837\u53EF\u4EE5\u5E2E\u52A9\u5F00\u53D1\u4EBA\u5458\u5FEB\u901F\u638C\u63E1\u95EE\u9898\u7684\u672C\u8D28\u3002</p><p><strong>\u6700\u540E\uFF0C\u7F3A\u9677\u6807\u9898\u4E0D\u6613\u8FC7\u957F\uFF0C\u5BF9\u7F3A\u9677\u66F4\u8BE6\u7EC6\u7684\u63CF\u8FF0\u5E94\u8BE5\u653E\u5728\u201C\u7F3A\u9677\u6982\u8FF0\u201D\u91CC</strong>\u3002</p><p><strong>\u7F3A\u9677\u6982\u8FF0</strong></p><p><em>\u7F3A\u9677\u6982\u8FF0\u901A\u5E38\u4F1A\u63D0\u4F9B\u66F4\u591A\u6982\u62EC\u6027\u7684\u7F3A\u9677\u672C\u8D28\u4E0E\u73B0\u8C61\u7684\u63CF\u8FF0</em>\uFF0C\u662F\u7F3A\u9677\u6807\u9898\u7684\u7EC6\u5316\u3002\u8FD9\u90E8\u5206\u5185\u5BB9\u901A\u5E38\u662F\u5F00\u53D1\u5DE5\u7A0B\u5E08\u6253\u5F00\u7F3A\u9677\u62A5\u544A\u540E\u6700\u5148\u5173\u6CE8\u7684\u5185\u5BB9\uFF0C\u6240\u4EE5\u7528\u6E05\u6670\u7B80\u77ED\u7684\u8BED\u53E5\u5C06\u95EE\u9898\u7684\u672C\u8D28\u63CF\u8FF0\u6E05\u695A\u662F\u5173\u952E\u3002</p><p>\u7F3A\u9677\u6982\u8FF0\u8FD8\u4F1A\u5305\u62EC\u7F3A\u9677\u7684\u5176\u4ED6\u5EF6\u5C55\u90E8\u5206\uFF0C\u6BD4\u5982\u4F60\u53EF\u4EE5\u5728\u8FD9\u90E8\u5206\u5217\u51FA\u540C\u4E00\u7C7B\u578B\u7684\u7F3A\u9677\u53EF\u80FD\u51FA\u73B0\u7684\u6240\u6709\u573A\u666F\uFF1B\u518D\u6BD4\u5982\uFF0C\u4F60\u8FD8\u53EF\u4EE5\u63CF\u8FF0\u540C\u6837\u7684\u95EE\u9898\u662F\u5426\u4F1A\u5728\u4E4B\u524D\u7684\u7248\u672C\u4E2D\u91CD\u73B0\u7B49\u3002\u5728\u8FD9\u91CC\uFF0C\u4F60\u5E94\u8BE5\u5C3D\u91CF\u907F\u514D\u4EE5\u7F3A\u9677\u91CD\u73B0\u6B65\u9AA4\u7684\u5F62\u5F0F\u6765\u63CF\u8FF0\uFF0C\u800C\u5E94\u8BE5\u4F7F\u7528\u6982\u62EC\u6027\u7684\u8BED\u53E5\u3002</p><p>\u603B\u4E4B\uFF0C<strong>\u7F3A\u9677\u6982\u8FF0\u7684\u76EE\u7684\u662F\uFF0C\u6E05\u6670\u7B80\u6D01\u5730\u63CF\u8FF0\u7F3A\u9677\uFF0C\u4F7F\u5F00\u53D1\u5DE5\u7A0B\u5E08\u80FD\u591F\u805A\u7126\u7F3A\u9677\u7684\u672C\u8D28</strong>\u3002</p><p><strong>\u7F3A\u9677\u5F71\u54CD</strong></p><p>\u7F3A\u9677\u5F71\u54CD\u63CF\u8FF0\u7684\u662F\uFF0C\u7F3A\u9677\u5F15\u8D77\u7684\u95EE\u9898\u5BF9\u7528\u6237\u6216\u8005\u5BF9\u4E1A\u52A1\u7684\u5F71\u54CD\u8303\u56F4\u4EE5\u53CA\u4E25\u91CD\u7A0B\u5EA6\u3002</p><p>\u7F3A\u9677\u5F71\u54CD\u51B3\u5B9A\u4E86\u7F3A\u9677\u7684\u4F18\u5148\u7EA7\uFF08Priority\uFF09\u548C\u4E25\u91CD\u7A0B\u5EA6\uFF08Severity\uFF09\uFF0C\u5F00\u53D1\u7ECF\u7406\u4F1A\u4EE5\u6B64\u4E3A\u4F9D\u636E\u6765\u51B3\u5B9A\u4FEE\u590D\u8BE5\u7F3A\u9677\u7684\u4F18\u5148\u7EA7\uFF1B\u800C\u4EA7\u54C1\u7ECF\u7406\u4F1A\u4EE5\u6B64\u4E3A\u4F9D\u636E\u6765\u8861\u91CF\u7F3A\u9677\u7684\u4E25\u91CD\u7A0B\u5EA6\uFF0C\u5E76\u51B3\u5B9A\u662F\u5426\u8981\u7B49\u8BE5\u7F3A\u9677\u88AB\u4FEE\u590D\u540E\u624D\u80FD\u53D1\u5E03\u4EA7\u54C1\u3002</p><p><strong>\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u51C6\u786E\u63CF\u8FF0\u7F3A\u9677\u5F71\u54CD\u7684\u524D\u63D0\u662F\uFF0C\u5FC5\u987B\u5BF9\u8F6F\u4EF6\u7684\u5E94\u7528\u573A\u666F\u4EE5\u53CA\u9700\u6C42\u6709\u6DF1\u5165\u7684\u7406\u89E3\uFF0C\u8FD9\u4E5F\u662F\u5BF9\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u4E1A\u52A1\u57FA\u672C\u529F\u7684\u8003\u9A8C</strong>\u3002</p><p><strong>\u73AF\u5883\u914D\u7F6E</strong></p><p><strong>\u73AF\u5883\u914D\u7F6E\u7528\u4EE5\u8BE6\u7EC6\u63CF\u8FF0\u6D4B\u8BD5\u73AF\u5883\u7684\u914D\u7F6E\u7EC6\u8282\uFF0C\u4E3A\u7F3A\u9677\u7684\u91CD\u73B0\u63D0\u4F9B\u5FC5\u8981\u7684\u73AF\u5883\u4FE1\u606F</strong>\u3002 \u6BD4\u5982\uFF0C\u64CD\u4F5C\u7CFB\u7EDF\u7684\u7C7B\u578B\u4E0E\u7248\u672C\u3001\u88AB\u6D4B\u8F6F\u4EF6\u7248\u672C\u3001\u6D4F\u89C8\u5668\u7684\u79CD\u7C7B\u548C\u7248\u672C\u3001\u88AB\u6D4B\u8F6F\u4EF6\u7684\u914D\u7F6E\u4FE1\u606F\u3001\u96C6\u7FA4\u7684\u914D\u7F6E\u53C2\u6570\u3001\u4E2D\u95F4\u4EF6\u7684\u7248\u672C\u4FE1\u606F\u7B49\u7B49\u3002</p><p><strong>\u9700\u8981\u6CE8\u610F\u7684\u662F\uFF0C\u73AF\u5883\u914D\u7F6E\u7684\u5185\u5BB9\u901A\u5E38\u662F\u6309\u9700\u63CF\u8FF0\uFF0C\u4E5F\u5C31\u662F\u8BF4\u901A\u5E38\u53EA\u63CF\u8FF0\u90A3\u4E9B\u91CD\u73B0\u7F3A\u9677\u7684\u73AF\u5883\u654F\u611F\u4FE1\u606F</strong>\u3002</p><p>\u6BD4\u5982\uFF0C\u201C\u83DC\u5355\u680F\u4E0A\u67D0\u4E2A\u6761\u76EE\u7F3A\u5931\u7684\u95EE\u9898\u201D\u53EA\u4F1A\u53D1\u751F\u5728 Chrome \u6D4F\u89C8\u5668\uFF0C\u800C\u5176\u4ED6\u6D4F\u89C8\u5668\u90FD\u6CA1\u6709\u7C7B\u4F3C\u95EE\u9898\u3002\u90A3\u4E48\uFF0CChrome \u6D4F\u89C8\u5668\u5C31\u662F\u73AF\u5883\u654F\u611F\u4FE1\u606F\uFF0C\u5FC5\u987B\u4E88\u4EE5\u63CF\u8FF0\uFF0C\u800C\u81F3\u4E8E Chrome \u6D4F\u89C8\u5668\u662F\u8FD0\u884C\u5728\u4EC0\u4E48\u64CD\u4F5C\u7CFB\u7EDF\u4E0A\u5C31\u65E0\u5173\u7D27\u8981\u4E86\uFF0C\u65E0\u9700\u7279\u610F\u53BB\u63CF\u8FF0\u4E86\u3002</p><p><strong>\u524D\u7F6E\u6761\u4EF6</strong></p><p><strong>\u524D\u7F6E\u6761\u4EF6\u662F\u6307\u6D4B\u8BD5\u6B65\u9AA4\u5F00\u59CB\u524D\u7CFB\u7EDF\u5E94\u8BE5\u5904\u5728\u7684\u72B6\u6001\uFF0C\u5176\u76EE\u7684\u662F\u51CF\u5C11\u7F3A\u9677\u91CD\u73B0\u6B65\u9AA4\u7684\u63CF\u8FF0\u3002\u5408\u7406\u5730\u4F7F\u7528\u524D\u7F6E\u6761\u4EF6\u53EF\u4EE5\u5728\u63CF\u8FF0\u7F3A\u9677\u91CD\u73B0\u6B65\u9AA4\u65F6\u6392\u9664\u4E0D\u5FC5\u8981\u7684\u5E72\u6270\uFF0C\u4F7F\u5176\u66F4\u6709\u9488\u5BF9\u6027</strong>\u3002</p><p>\u6BD4\u5982\uFF0C\u67D0\u4E2A\u4E1A\u52A1\u64CD\u4F5C\u9700\u8981\u5148\u5B8C\u6210\u7528\u6237\u767B\u5F55\uFF0C\u4F60\u5728\u7F3A\u9677\u91CD\u73B0\u6B65\u9AA4\u91CC\u5C31\u6CA1\u6709\u5FC5\u8981\u63CF\u8FF0\u767B\u5F55\u64CD\u4F5C\u7684\u6B65\u9AA4\u7EC6\u8282\uFF0C\u53EF\u4EE5\u76F4\u63A5\u4F7F\u7528 \u201C\u524D\u7F6E\u6761\u4EF6\uFF1A\u7528\u6237\u5DF2\u5B8C\u6210\u767B\u5F55\u201D\u7684\u63CF\u8FF0\u65B9\u5F0F\uFF1B</p><p>\u518D\u6BD4\u5982\uFF0C\u7528\u6237\u5728\u6267\u884C\u767B\u5F55\u64CD\u4F5C\u524D\uFF0C\u9700\u8981\u4E8B\u5148\u5728\u88AB\u6D4B\u7CFB\u7EDF\u51C6\u5907\u597D\u5F85\u767B\u5F55\u7528\u6237\uFF0C\u4F60\u5728\u63CF\u8FF0\u65F6\u4E5F\u65E0\u9700\u589E\u52A0\u201C\u7528\u6D4B\u8BD5\u6570\u636E\u751F\u6210\u5DE5\u5177\u751F\u6210\u7528\u6237\u201D\u7684\u6B65\u9AA4\uFF0C\u53EF\u4EE5\u76F4\u63A5\u4F7F\u7528 \u201C\u524D\u7F6E\u6761\u4EF6\uFF1A\u7528\u6237\u5DF2\u5B8C\u6210\u6CE8\u518C\u201D\u7684\u63CF\u8FF0\u65B9\u5F0F\u3002</p><p><strong>\u7F3A\u9677\u91CD\u73B0\u6B65\u9AA4</strong></p><p><em>\u7F3A\u9677\u91CD\u73B0\u6B65\u9AA4\u662F\u6574\u4E2A\u7F3A\u9677\u62A5\u544A\u4E2D\u6700\u6838\u5FC3\u7684\u5185\u5BB9\uFF0C\u5176\u76EE\u7684\u5728\u4E8E\u7528\u7B80\u6D01\u7684\u8BED\u8A00\u5411\u5F00\u53D1\u5DE5\u7A0B\u5E08\u5C55\u793A\u7F3A\u9677\u91CD\u73B0\u7684\u5177\u4F53\u64CD\u4F5C\u6B65\u9AA4</em>\u3002</p><p>\u8FD9\u91CC\u9700\u8981\u6CE8\u610F\u7684\u662F\uFF0C<strong>\u64CD\u4F5C\u6B65\u9AA4\u901A\u5E38\u662F\u4ECE\u7528\u6237\u89D2\u5EA6\u51FA\u53D1\u6765\u63CF\u8FF0\u7684\uFF0C\u6BCF\u4E2A\u6B65\u9AA4\u90FD\u5E94\u8BE5\u662F\u53EF\u64CD\u4F5C\u5E76\u4E14\u662F\u8FDE\u8D2F\u7684\uFF0C\u6240\u4EE5\u5F80\u5F80\u4F1A\u91C7\u7528\u6B65\u9AA4\u5217\u8868\u7684\u8868\u73B0\u5F62\u5F0F</strong>\u3002</p><p>\u901A\u5E38\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u5728\u5199\u7F3A\u9677\u91CD\u73B0\u6B65\u9AA4\u524D\uFF0C\u9700\u8981\u53CD\u590D\u6267\u884C\u8FD9\u4E9B\u6B65\u9AA4 3 \u6B21\u4EE5\u4E0A\uFF1A\u4E00\u662F\uFF0C\u786E\u4FDD\u7F3A\u9677\u7684\u53EF\u91CD\u73B0\u6027\uFF1B\u4E8C\u662F\uFF0C\u627E\u5230\u6700\u77ED\u7684\u91CD\u73B0\u8DEF\u5F84\uFF0C\u8FC7\u6EE4\u6389\u90A3\u4E9B\u975E\u5FC5\u8981\u7684\u6B65\u9AA4\uFF0C\u907F\u514D\u4EA7\u751F\u4E0D\u5FC5\u8981\u7684\u5E72\u6270\u3002</p><p>\u5BF9\u4E8E\u7F3A\u9677\u91CD\u73B0\u6B65\u9AA4\u7684\u63CF\u8FF0\u5E94\u8BE5\u5C3D\u91CF\u907F\u514D\u4EE5\u4E0B 3 \u4E2A\u5E38\u89C1\u95EE\u9898\uFF1A</p><ol><li>\u7B3C\u7EDF\u7684\u63CF\u8FF0\uFF0C\u7F3A\u4E4F\u53EF\u64CD\u4F5C\u7684\u5177\u4F53\u6B65\u9AA4\u3002</li><li>\u51FA\u73B0\u4E0E\u7F3A\u9677\u91CD\u73B0\u4E0D\u76F8\u5173\u7684\u6B65\u9AA4\u3002</li><li>\u7F3A\u4E4F\u5BF9\u6D4B\u8BD5\u6570\u636E\u7684\u76F8\u5173\u63CF\u8FF0\u3002</li></ol><p><strong>\u671F\u671B\u7ED3\u679C\u548C\u5B9E\u9645\u7ED3\u679C</strong></p><p>\u671F\u671B\u7ED3\u679C\u548C\u5B9E\u9645\u7ED3\u679C\u901A\u5E38\u548C\u7F3A\u9677\u91CD\u73B0\u6B65\u9AA4\u7ED1\u5B9A\u5728\u4E00\u8D77\uFF0C\u5728\u63CF\u8FF0\u91CD\u73B0\u6B65\u9AA4\u7684\u8FC7\u7A0B\u4E2D\uFF0C\u9700\u8981\u660E\u786E\u8BF4\u660E\u671F\u5F85\u7ED3\u679C\u548C\u5B9E\u9645\u7ED3\u679C\u3002\u671F\u5F85\u7ED3\u679C\u6765\u81EA\u4E8E\u5BF9\u9700\u6C42\u7684\u7406\u89E3\uFF0C\u800C\u5B9E\u9645\u7ED3\u679C\u6765\u81EA\u4E8E\u6D4B\u8BD5\u6267\u884C\u7684\u7ED3\u679C\u3002</p><p>\u901A\u5E38\u6765\u8BB2\uFF0C<strong>\u5F53\u4F60\u63CF\u8FF0\u671F\u671B\u7ED3\u679C\u65F6\uFF0C\u9700\u8981\u8BF4\u660E\u5E94\u8BE5\u53D1\u751F\u4EC0\u4E48\uFF0C\u800C\u4E0D\u662F\u4EC0\u4E48\u4E0D\u5E94\u8BE5\u53D1\u751F\uFF1B\u800C\u63CF\u8FF0\u5B9E\u9645\u7ED3\u679C\u65F6\uFF0C\u4F60\u5E94\u8BE5\u8BF4\u660E\u53D1\u751F\u4E86\u4EC0\u4E48\uFF0C\u800C\u4E0D\u662F\u4EC0\u4E48\u6CA1\u6709\u53D1\u751F</strong>\u3002</p><p><strong>\u4F18\u5148\u7EA7\uFF08Priority\uFF09\u548C\u4E25\u91CD\u7A0B\u5EA6\uFF08Severity\uFF09</strong></p><p>\u6211\u4E4B\u6240\u4EE5\u5C06\u4F18\u5148\u7EA7\u548C\u4E25\u91CD\u7A0B\u5EA6\u653E\u5728\u4E00\u8D77\uFF0C\u662F\u56E0\u4E3A\u8FD9\u4E24\u4E2A\u6982\u5FF5\u770B\u8D77\u6765\u6709\u70B9\u7C7B\u4F3C\uFF0C\u800C\u672C\u8D28\u5374\u5B8C\u5168\u4E0D\u540C\u3002\u800C\u4E14\uFF0C\u5F88\u591A\u5165\u884C\u4E0D\u4E45\u7684\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\uFF0C\u4E5F\u5F88\u96BE\u641E\u6E05\u695A\u8FD9\u4E24\u8005\u7684\u5DEE\u5F02\u5230\u5E95\u5728\u54EA\u91CC\u3002</p><p>\u6839\u636E\u767E\u5EA6\u767E\u79D1\u7684\u89E3\u91CA\uFF0C\u7F3A\u9677\u4F18\u5148\u7EA7\u662F\u6307\u7F3A\u9677\u5FC5\u987B\u88AB\u4FEE\u590D\u7684\u7D27\u6025\u7A0B\u5EA6\uFF0C\u800C\u7F3A\u9677\u4E25\u91CD\u7A0B\u5EA6\u662F\u6307\u56E0\u7F3A\u9677\u5F15\u8D77\u7684\u6545\u969C\u5BF9\u8F6F\u4EF6\u4EA7\u54C1\u7684\u5F71\u54CD\u7A0B\u5EA6\u3002</p><p>\u53EF\u89C1\uFF0C<em>\u4E25\u91CD\u7A0B\u5EA6\u662F\u7F3A\u9677\u672C\u8EAB\u7684\u5C5E\u6027\uFF0C\u901A\u5E38\u786E\u5B9A\u540E\u5C31\u4E0D\u518D\u53D8\u5316\uFF0C\u800C\u4F18\u5148\u7EA7\u662F\u7F3A\u9677\u7684\u5DE5\u7A0B\u5C5E\u6027\uFF0C\u4F1A\u968F\u7740\u9879\u76EE\u8FDB\u5EA6\u3001\u89E3\u51B3\u7F3A\u9677\u7684\u6210\u672C\u7B49\u56E0\u7D20\u800C\u53D8\u52A8</em>\u3002\u90A3\u4E48\uFF0C\u7F3A\u9677\u7684\u4F18\u5148\u7EA7\u548C\u4E25\u91CD\u7A0B\u5EA6\u53C8\u6709\u4EC0\u4E48\u5173\u7CFB\u5462\uFF1F</p><ol><li>\u7F3A\u9677\u8D8A\u4E25\u91CD\uFF0C\u4F18\u5148\u7EA7\u5C31\u8D8A\u9AD8\uFF1B</li><li>\u7F3A\u9677\u5F71\u54CD\u7684\u8303\u56F4\u8D8A\u5927\uFF0C\u4F18\u5148\u7EA7\u4E5F\u4F1A\u8D8A\u9AD8\uFF1B</li><li>\u6709\u4E9B\u7F3A\u9677\u867D\u7136\u4ECE\u7528\u6237\u5F71\u54CD\u89D2\u5EA6\u6765\u8BF4\u4E0D\u7B97\u4E25\u91CD\uFF0C\u4F46\u662F\u4F1A\u59A8\u788D\u6D4B\u8BD5\u6216\u8005\u662F\u81EA\u52A8\u5316\u6D4B\u8BD5\u7684\u6267\u884C\uFF0C\u8FD9\u7C7B\u7F3A\u9677\u5C5E\u4E8E\u5178\u578B\u7684\u4E25\u91CD\u7A0B\u5EA6\u4F4E\uFF0C\u4F46\u662F\u4F18\u5148\u7EA7\u9AD8\uFF1B</li><li>\u6709\u4E9B\u7F3A\u9677\u867D\u7136\u4E25\u91CD\u7A0B\u5EA6\u6BD4\u8F83\u9AD8\uFF0C\u4F46\u662F\u8003\u8651\u5230\u4FEE\u590D\u6210\u672C\u4EE5\u53CA\u6280\u672F\u96BE\u5EA6\uFF0C\u4E5F\u4F1A\u51FA\u73B0\u4F18\u5148\u7EA7\u8F83\u4F4E\u7684\u60C5\u51B5\u3002</li></ol><p><strong>\u53D8\u901A\u65B9\u6848\uFF08Workaround\uFF09</strong></p><p>\u53D8\u901A\u65B9\u6848\u662F\u63D0\u4F9B\u4E00\u79CD\u4E34\u65F6\u7ED5\u5F00\u5F53\u524D\u7F3A\u9677\u800C\u4E0D\u5F71\u54CD\u4EA7\u54C1\u529F\u80FD\u7684\u65B9\u5F0F\uFF0C\u901A\u5E38\u7531\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u6216\u8005\u5F00\u53D1\u5DE5\u7A0B\u5E08\u5B8C\u6210\uFF0C\u6216\u8005\u4ED6\u4EEC\u4E00\u540C\u51B3\u5B9A\u3002</p><p>\u53D8\u901A\u65B9\u6848\u7684\u6709\u65E0\u4EE5\u53CA\u5B9E\u65BD\u7684\u96BE\u6613\u7A0B\u5EA6\uFF0C\u662F\u51B3\u5B9A\u7F3A\u9677\u4F18\u5148\u7EA7\u548C\u4E25\u91CD\u7A0B\u5EA6\u7684\u91CD\u8981\u4F9D\u636E\u3002\u5982\u679C\u67D0\u4E2A\u4E25\u91CD\u7684\u7F3A\u9677\u6CA1\u6709\u4EFB\u4F55\u53EF\u884C\u7684\u53D8\u901A\u65B9\u6848\uFF0C\u90A3\u4E48\u4E0D\u7BA1\u4FEE\u590D\u7F3A\u9677\u4EE3\u4EF7\u6709\u591A\u5927\uFF0C\u4F18\u5148\u7EA7\u4E00\u5B9A\u4F1A\u662F\u6700\u9AD8\u7684\uFF0C\u4F46\u662F\u5982\u679C\u8BE5\u7F3A\u9677\u5B58\u5728\u6BD4\u8F83\u7B80\u5355\u7684\u53D8\u901A\u65B9\u6848\uFF0C\u90A3\u4E48\u4F18\u5148\u7EA7\u5C31\u4E0D\u4E00\u5B9A\u4F1A\u662F\u6700\u9AD8\u7684\u4E86\u3002</p><p><strong>\u6839\u539F\u56E0\u5206\u6790\uFF08Root Cause Analysis\uFF09</strong></p><p>\u6839\u539F\u56E0\u5206\u6790\u5C31\u662F\u6211\u4EEC\u5E73\u65F6\u5E38\u8BF4\u7684 RCA\uFF0C\u5982\u679C\u4F60\u80FD\u5728\u53D1\u73B0\u7F3A\u9677\u7684\u540C\u65F6\uFF0C\u5B9A\u4F4D\u51FA\u95EE\u9898\u7684\u6839\u672C\u539F\u56E0\uFF0C\u6E05\u695A\u5730\u63CF\u8FF0\u7F3A\u9677\u4EA7\u751F\u7684\u539F\u56E0\u5E76\u53CD\u9988\u7ED9\u5F00\u53D1\u5DE5\u7A0B\u5E08\uFF0C\u90A3\u4E48\u5F00\u53D1\u5DE5\u7A0B\u5E08\u4FEE\u590D\u7F3A\u9677\u7684\u6548\u7387\u5C31\u4F1A\u5927\u5E45\u63D0\u5347\uFF0C\u800C\u4E14\u4F60\u7684\u6280\u672F\u5F71\u54CD\u529B\u4E5F\u4F1A\u88AB\u5F00\u53D1\u8BA4\u53EF\u3002</p><p>\u53EF\u4EE5\u505A\u597D\u6839\u539F\u56E0\u5206\u6790\u7684\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\uFF0C\u901A\u5E38\u90FD\u5177\u6709\u5F00\u53D1\u80CC\u666F\uFF0C\u6216\u8005\u81F3\u5C11\u6709\u8F83\u597D\u7684\u4EE3\u7801\u9605\u8BFB\u4EE5\u53CA\u4EE3\u7801\u8C03\u8BD5\u7684\u80FD\u529B\u3002</p><p>\u6240\u4EE5\u505A\u4E3A\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\uFF0C\u4F60\u5F88\u6709\u5FC5\u8981\u53BB\u6DF1\u5165\u5B66\u4E60\u4E00\u95E8\u9AD8\u7EA7\u8BED\u8A00\uFF0C\u8FD9\u5C06\u5E2E\u52A9\u4F60\u4F53\u7CFB\u5316\u5730\u5EFA\u7ACB\u8D77\u7F16\u7A0B\u601D\u60F3\u548C\u65B9\u6CD5\uFF0C\u8FD9\u6837\u5728\u4E4B\u540E\u7684\u5DE5\u4F5C\u4E2D\uFF0C\u65E0\u8BBA\u4F60\u662F\u9762\u5BF9\u5F00\u53D1\u7684\u4EE3\u7801\uFF0C\u8FD8\u662F\u81EA\u52A8\u5316\u6D4B\u8BD5\u4EE3\u7801\u548C\u811A\u672C\u90FD\u80FD\u505A\u5230\u5F97\u5FC3\u5E94\u624B\uFF0C\u5E94\u5BF9\u81EA\u5982\u3002</p><p><strong>\u9644\u4EF6\uFF08Attachment\uFF09</strong></p><p>\u9644\u4EF6\u901A\u5E38\u662F\u4E3A\u7F3A\u9677\u7684\u5B58\u5728\u63D0\u4F9B\u5FC5\u8981\u7684\u8BC1\u636E\u652F\u6301\uFF0C\u5E38\u89C1\u7684\u9644\u4EF6\u6709\u754C\u9762\u622A\u56FE\u3001\u6D4B\u8BD5\u7528\u4F8B\u65E5\u5FD7\u3001\u670D\u52A1\u5668\u7AEF\u65E5\u5FD7\u3001GUI \u6D4B\u8BD5\u7684\u6267\u884C\u89C6\u9891\u7B49\u3002</p><p>\u5BF9\u4E8E\u90A3\u4E9B\u5F88\u96BE\u7528\u6587\u5B57\u63CF\u8FF0\u6E05\u695A\u7684 GUI \u754C\u9762\u5E03\u5C40\u7684\u7F3A\u9677\uFF0C\u4F60\u53EF\u4EE5\u91C7\u7528\u622A\u56FE\u5E76\u9AD8\u4EAE\u663E\u793A\u5E94\u8BE5\u5173\u6CE8\u7684\u533A\u57DF\u7684\u65B9\u5F0F\u53BB\u63D0\u4EA4\u7F3A\u9677\u62A5\u544A\u3002</p><p><strong>\u603B\u7ED3</strong></p><p>\u7F3A\u9677\u62A5\u544A\u662F\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u4E0E\u5F00\u53D1\u5DE5\u7A0B\u5E08\u4EA4\u6D41\u6C9F\u901A\u7684\u91CD\u8981\u6865\u6881\uFF0C\u4E5F\u662F\u6D4B\u8BD5\u5DE5\u7A0B\u5E08\u65E5\u5E38\u5DE5\u4F5C\u7684\u91CD\u8981\u8F93\u51FA\u3002</p><p>\u4E00\u4EFD\u9AD8\u6548\u7684\u8F6F\u4EF6\u7F3A\u9677\u62A5\u544A\uFF0C\u5E94\u8BE5\u5305\u62EC\u7F3A\u9677\u6807\u9898\u3001\u7F3A\u9677\u6982\u8FF0\u3001\u7F3A\u9677\u5F71\u54CD\u3001\u73AF\u5883\u914D\u7F6E\u3001\u524D\u7F6E\u6761\u4EF6\u3001\u7F3A\u9677\u91CD\u73B0\u6B65\u9AA4\u3001\u671F\u671B\u7ED3\u679C\u548C\u5B9E\u9645\u7ED3\u679C\u3001\u4F18\u5148\u7EA7\u548C\u4E25\u91CD\u7A0B\u5EA6\u3001\u53D8\u901A\u65B9\u6848\u3001\u6839\u539F\u56E0\u5206\u6790\uFF0C\u4EE5\u53CA\u9644\u4EF6\u8FD9\u51E0\u5927\u90E8\u5206\u3002</p><p>\u7F3A\u9677\u62A5\u544A\u7684\u6BCF\u4E00\u90E8\u5206\u5185\u5BB9\uFF0C\u90FD\u4F1A\u56E0\u4E3A\u76EE\u7684\u3001\u8868\u73B0\u5F62\u5F0F\u6709\u5404\u81EA\u7684\u4FA7\u91CD\u70B9\uFF0C\u6240\u4EE5\u60F3\u8981\u5199\u51FA\u4E00\u4EFD\u9AD8\u6548\u7684\u8F6F\u4EF6\u7F3A\u9677\u62A5\u544A\uFF0C\u9700\u8981\u5BF9\u5176\u7EC4\u6210\u6709\u6DF1\u5165\u7684\u7406\u89E3\u3002</p><p><strong>\u601D\u8003\u9898</strong></p><p>\u5173\u4E8E\u9AD8\u6548\u586B\u5199\u8F6F\u4EF6\u7F3A\u9677\u62A5\u544A\uFF0C\u4F60\u8FD8\u6709\u54EA\u4E9B\u597D\u7684\u5B9E\u8DF5\uFF1F</p>',66);function n(s,g){return o}var i=p(t,[["render",n],["__file","07.html.vue"]]);export{i as default};
